#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;

NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5,dx[]={0,1,0,-1,1,1,-1,-1,0,2,0,-2},dy[]={1,0,-1,0,1,-1,1,-1,2,0,-2,0},dw[]={0,0,0,0,2,2,2,2,2,2,2,2};
vector<PII> g[MAXN];
int n,m,S,T,dis[MAXN];
void dijkstra()
{
    cli(dis);
    priority_queue<PII,vector<PII>,greater<PII>> q;
    dis[S]=0;
    q.push(mk(0,S));
    wh(!q.empty())
    {
        int d=q.top().fst,x=q.top().snd;
        q.pop();
        if(d>dis[x])continue;
        FOI(e,g[x])
        {
            int y=e.fst,w=e.snd;
            if(dis[y]>dis[x]+w)
            {
                dis[y]=dis[x]+w;
                q.push(mk(dis[y],y));
            }
        }
    }
}
int a[105][105],cnt[105][105];
struct node
{
    int x,y,c;
}b[MAXN];
signed main(void)
{
    m=read(),n=read();
    FOR(i,1,n)
    {
        int x=read(),y=read(),c=read();
        a[x][y]=c+1;
        cnt[x][y]=i;
        b[i]=(node){x,y,c+1};
    }
    FOR(i,1,n)
    {
        int now_x=b[i].x,now_y=b[i].y,now_c=b[i].c;
        FOR(j,0,11)
        {
            int new_x=now_x+dx[j];
            int new_y=now_y+dy[j];
            int ww=dw[j];
            if(a[new_x][new_y])
            {
                if(a[new_x][new_y]!=now_c)++ww;
                g[i].pb(mk(cnt[new_x][new_y],ww));
            }
        }
    }
    S=cnt[1][1];
    dijkstra();
    if(!a[m][m])
    {
        int ans=min(dis[cnt[m][m-1]],dis[cnt[m-1][m]])+2;
        if(ans>=inf)NoAns
        else writeln(ans);
    }
    else
    {
        if(dis[cnt[m][m]]==inf)NoAns
        else writeln(dis[cnt[m][m]]);
    }
    return false;
}
